public class Alipay implements PaymentStrategy {
    public void pay(Order order) { System.out.println("订单 " + order.getOrderId() + " 使用支付宝支付了 " + order.getAmount() + " 元"); }
}

// PaymentProcessor.java
public class PaymentProcessor {
    private PaymentStrategy strategy;
    public void setPaymentStrategy(PaymentStrategy strategy) { this.strategy = strategy; }
    public void processPayment(Order order) {
        if (strategy == null) { System.out.println("未设置支付方式！"); return; }
        strategy.pay(order);
    }
}

// Main.java
public class Main {
    public static void main(String[] args) {
        PaymentProcessor processor = new PaymentProcessor();
        Order order2 = new Order("ORD002", 200.0);
        processor.setPaymentStrategy(new WechatPay());
        processor.processPayment(order2);
        Order order3 = new Order("ORD003", 300.0);
        processor.setPaymentStrategy(new Alipay());
        processor.processPayment(order3);
    }
}
